113			slice = slice[:*first]
114			truncByFirst = true
115		}
116		pageInfo := &PageInfo{
117			HasPreviousPage: startIdx > 0,
118			HasNextPage:     truncByFirst,
119		}
120		if len(slice) > 0 {
121			pageInfo.StartCursor = &slice[0].Cursor
122			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
123		}
124		return &RunToolCallConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
125	}
126	
127	func emptyRunConnection() *RunConnection {
128		return &RunConnection{Edges: []*RunEdge{}, PageInfo: &PageInfo{}, TotalCount: 0}
129	}
130	
131	func runConnectionFrom(runs []*Run, first *int, after *string) *RunConnection {
132		all := make([]*RunEdge, len(runs))
133		ids := make([]string, len(runs))
134		for i, r := range runs {
135			all[i] = &RunEdge{Node: r, Cursor: encodeStableCursor(r.ID)}
136			ids[i] = r.ID
137		}
138		startIdx, _ := stablePageBounds(ids, after, nil)
139		slice := all[startIdx:]
140		truncByFirst := false
141		if first != nil && *first >= 0 && *first < len(slice) {
142			slice = slice[:*first]
143			truncByFirst = true
144		}
145		pageInfo := &PageInfo{
146			HasPreviousPage: startIdx > 0,
147			HasNextPage:     truncByFirst,
148		}
149		if len(slice) > 0 {
150			pageInfo.StartCursor = &slice[0].Cursor
151			pageInfo.EndCursor = &slice[len(slice)-1].Cursor
152		}
153		return &RunConnection{Edges: slice, PageInfo: pageInfo, TotalCount: len(all)}
154	}
155	
156	// ApplyRunFilter applies the filter to a list of runs. Exported so state_runs.go can call it.
157	func ApplyRunFilter(in []*Run, filter RunFilter) []*Run {
158		return applyRunFilter(in, filter)
159	}
160	
161	// applyRunFilter applies the filter to a list of runs.
162	func applyRunFilter(in []*Run, filter RunFilter) []*Run {
163		if len(in) == 0 {
164			return in
165		}
166		if filter.Layer == nil && filter.BeadID == "" && filter.Status == "" && filter.Harness == "" {
167			return in
168		}
169		out := in[:0:0]
170		for _, r := range in {
171			if filter.Layer != nil && r.Layer != *filter.Layer {
172				continue
173			}
174			if filter.BeadID != "" {
175				if r.BeadID == nil || *r.BeadID != filter.BeadID {
176					continue
177				}
178			}
179			if filter.Status != "" {
180				if !strings.EqualFold(r.Status, filter.Status) {
181					continue
182				}
183			}
184			if filter.Harness != "" {
185				if r.Harness == nil || *r.Harness != filter.Harness {
186					continue
187				}
188			}
189			out = append(out, r)
190		}
191		return out
192	}
