376	// GetRunBundleFileGraphQL is the data-layer entry point for the
377	// runBundleFile(id, path) resolver. Returns (nil, false) when the run is
378	// unknown, the path fails confinement, or the file does not exist.
379	func (s *ServerState) GetRunBundleFileGraphQL(id, path string) (*ddxgraphql.RunBundleFileContent, bool) {
380		bundleRoot, _, ok := s.runBundleRoot(id)
381		if !ok {
382			return nil, false
383		}
384		return readRunBundleFile(bundleRoot, path)
385	}
